import { useEffect, useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';

import ArrowLeftOutlined from '@ant-design/icons/ArrowLeftOutlined';
import Button from '@mui/material/Button';
import Chip from '@mui/material/Chip';
import Grid from '@mui/material/Grid';
import Stack from '@mui/material/Stack';
import Table from '@mui/material/Table';
import TableBody from '@mui/material/TableBody';
import TableCell from '@mui/material/TableCell';
import TableHead from '@mui/material/TableHead';
import TableRow from '@mui/material/TableRow';
import Typography from '@mui/material/Typography';

import MainCard from 'components/MainCard';
import { EmptyState, ErrorState, LoadingState } from 'components/common/PageFeedback';
import apiClient from 'lib/http/apiClient';
import extractApiErrorMessage from 'utils/apiError';

function SimpleDataTable({ title, columns, rows }) {
  return (
    <MainCard title={title}>
      {!rows?.length ? (
        <EmptyState message="Sin registros" />
      ) : (
        <Table size="small">
          <TableHead>
            <TableRow>
              {columns.map((column) => (
                <TableCell key={column.key}>{column.label}</TableCell>
              ))}
            </TableRow>
          </TableHead>
          <TableBody>
            {rows.map((row, index) => (
              <TableRow key={row.id || `${title}-${index}`}>
                {columns.map((column) => (
                  <TableCell key={`${row.id || row[column.key] || index}-${column.key}`}>
                    {column.render ? column.render(row) : row[column.key] || '-'}
                  </TableCell>
                ))}
              </TableRow>
            ))}
          </TableBody>
        </Table>
      )}
    </MainCard>
  );
}

export default function ParcelDetailPage() {
  const { parcelId } = useParams();
  const navigate = useNavigate();

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [parcel, setParcel] = useState(null);

  useEffect(() => {
    let mounted = true;

    async function load() {
      try {
        const response = await apiClient.get(`/parcelas/${parcelId}/ficha-consolidada/`);
        if (!mounted) return;
        setParcel(response.data);
      } catch (err) {
        if (!mounted) return;
        setError(extractApiErrorMessage(err, 'No se pudo cargar la ficha consolidada.'));
      } finally {
        if (mounted) setLoading(false);
      }
    }

    load();
    return () => {
      mounted = false;
    };
  }, [parcelId]);

  const summaryCards = useMemo(() => {
    if (!parcel) return [];
    return [
      { label: 'Propietarios', value: parcel.owners?.length || 0 },
      { label: 'Residentes', value: parcel.residents?.length || 0 },
      { label: 'Vehículos', value: parcel.vehicles?.length || 0 },
      { label: 'Deudas GC', value: parcel.common_expense_debts?.length || 0 },
      { label: 'Deudas AyS', value: parcel.service_debts?.length || 0 },
      { label: 'Cortes', value: parcel.service_cuts?.filter((cut) => cut.activo).length || 0 }
    ];
  }, [parcel]);

  if (loading) return <LoadingState />;
  if (error) return <ErrorState message={error} />;
  if (!parcel) return <EmptyState message="Parcela no encontrada" />;

  return (
    <Stack sx={{ gap: 2.5 }}>
      <Stack direction={{ xs: 'column', md: 'row' }} sx={{ justifyContent: 'space-between', gap: 1.5 }}>
        <Stack>
          <Typography variant="h3">Ficha Consolidada Parcela {parcel.codigo_parcela}</Typography>
          <Typography variant="body2" color="text.secondary">
            Estado: <Chip label={parcel.estado} size="small" sx={{ ml: 1 }} />
          </Typography>
        </Stack>
        <Button startIcon={<ArrowLeftOutlined />} onClick={() => navigate('/parcelas')}>
          Volver al listado
        </Button>
      </Stack>

      <Grid container spacing={2}>
        {summaryCards.map((item) => (
          <Grid key={item.label} size={{ xs: 12, sm: 6, md: 4, lg: 2 }}>
            <MainCard contentSX={{ p: 2 }}>
              <Typography variant="caption" color="text.secondary">
                {item.label}
              </Typography>
              <Typography variant="h4">{item.value}</Typography>
            </MainCard>
          </Grid>
        ))}
      </Grid>

      <MainCard title="Datos generales">
        <Grid container spacing={2}>
          <Grid size={{ xs: 12, md: 4 }}>
            <Typography variant="caption" color="text.secondary">
              Código
            </Typography>
            <Typography variant="body1">{parcel.codigo_parcela}</Typography>
          </Grid>
          <Grid size={{ xs: 12, md: 4 }}>
            <Typography variant="caption" color="text.secondary">
              Lote
            </Typography>
            <Typography variant="body1">
              {parcel.letra_lote}-{parcel.numero_lote}
              {parcel.sufijo_lote || ''}
            </Typography>
          </Grid>
          <Grid size={{ xs: 12, md: 4 }}>
            <Typography variant="caption" color="text.secondary">
              Referencia
            </Typography>
            <Typography variant="body1">{parcel.referencia_direccion || '-'}</Typography>
          </Grid>
          <Grid size={12}>
            <Typography variant="caption" color="text.secondary">
              Observaciones
            </Typography>
            <Typography variant="body1">{parcel.observaciones_generales || '-'}</Typography>
          </Grid>
        </Grid>
      </MainCard>

      <SimpleDataTable
        title="Propietarios y Copropietarios"
        columns={[
          { key: 'tipo', label: 'Tipo' },
          { key: 'nombre', label: 'Nombre', render: (row) => row.persona?.nombre_completo || '-' },
          { key: 'rut', label: 'RUT', render: (row) => (row.persona?.rut ? `${row.persona.rut}-${row.persona.rut_dv || ''}` : '-') },
          { key: 'email', label: 'Email', render: (row) => row.persona?.email || '-' },
          { key: 'telefono', label: 'Teléfono', render: (row) => row.persona?.telefono_principal || '-' }
        ]}
        rows={parcel.owners || []}
      />

      <SimpleDataTable
        title="Residentes"
        columns={[
          { key: 'tipo_residencia', label: 'Tipo' },
          { key: 'nombre', label: 'Persona', render: (row) => row.persona?.nombre_completo || 'Sin persona asociada' },
          { key: 'is_active', label: 'Activo', render: (row) => (row.is_active ? 'Sí' : 'No') },
          { key: 'observaciones', label: 'Observaciones' }
        ]}
        rows={parcel.residents || []}
      />

      <SimpleDataTable
        title="Vehículos"
        columns={[
          { key: 'ppu', label: 'Patente/PPU' },
          { key: 'marca', label: 'Marca' },
          { key: 'modelo', label: 'Modelo' },
          { key: 'tipo', label: 'Tipo' },
          { key: 'color', label: 'Color' }
        ]}
        rows={parcel.vehicles || []}
      />

      <Grid container spacing={2}>
        <Grid size={{ xs: 12, lg: 6 }}>
          <SimpleDataTable
            title="Deudas Gastos Comunes"
            columns={[
              { key: 'numero_gastos_comunes', label: 'N° GC' },
              { key: 'total_pesos', label: 'Total CLP' },
              { key: 'estado_pago', label: 'Estado' }
            ]}
            rows={parcel.common_expense_debts || []}
          />
        </Grid>
        <Grid size={{ xs: 12, lg: 6 }}>
          <SimpleDataTable
            title="Deudas Agua y Servicios"
            columns={[
              { key: 'tipo_servicio', label: 'Tipo' },
              { key: 'saldo_total', label: 'Saldo' },
              { key: 'estado_pago', label: 'Estado' }
            ]}
            rows={parcel.service_debts || []}
          />
        </Grid>
      </Grid>

      <SimpleDataTable
        title="Servicios y Cortes"
        columns={[
          { key: 'tipo_corte', label: 'Tipo corte' },
          { key: 'estado', label: 'Estado' },
          { key: 'fecha', label: 'Fecha' },
          { key: 'motivo', label: 'Motivo' },
          { key: 'activo', label: 'Vigente', render: (row) => (row.activo ? 'Sí' : 'No') }
        ]}
        rows={parcel.service_cuts || []}
      />

      <SimpleDataTable
        title="Anotaciones"
        columns={[
          { key: 'tipo', label: 'Tipo' },
          { key: 'fecha_evento', label: 'Fecha' },
          { key: 'texto', label: 'Texto' }
        ]}
        rows={parcel.notes || []}
      />

      <MainCard title="Estado de obras / terreno">
        {parcel.work_status ? (
          <Grid container spacing={2}>
            <Grid size={{ xs: 12, md: 4 }}>
              <Typography variant="caption" color="text.secondary">
                Estado actual
              </Typography>
              <Typography variant="body1">{parcel.work_status.estado_actual || '-'}</Typography>
            </Grid>
            <Grid size={{ xs: 12, md: 4 }}>
              <Typography variant="caption" color="text.secondary">
                KPI
              </Typography>
              <Typography variant="body1">{parcel.work_status.kpi || '-'}</Typography>
            </Grid>
            <Grid size={{ xs: 12, md: 4 }}>
              <Typography variant="caption" color="text.secondary">
                Foco incendio
              </Typography>
              <Typography variant="body1">{parcel.work_status.foco_incendio || '-'}</Typography>
            </Grid>
            <Grid size={12}>
              <Typography variant="caption" color="text.secondary">
                Observaciones
              </Typography>
              <Typography variant="body1">{parcel.work_status.observaciones || '-'}</Typography>
            </Grid>
          </Grid>
        ) : (
          <EmptyState message="Sin información de obras." />
        )}
      </MainCard>
    </Stack>
  );
}
